        public int SelectedPeak
        {
            get => selectedPeak >= Data?.InjectionCount ? Data.InjectionCount - 1 : selectedPeak;
            set
            {
                if (value == -1)
                {
                    selectedPeak = value;
                    if (CurrentHorizontalZoomMode == HorizontalZoomMode.SelectedPeak)
                    {
                        CurrentHorizontalZoomMode = HorizontalZoomMode.None;
                        ZoomModeChanged?.Invoke(this, EventArgs.Empty);
                    }
                }
                else
                {
                    selectedPeak = value;

                    if (selectedPeak < 0) selectedPeak = 0;
                    else if (selectedPeak >= Data.InjectionCount) selectedPeak = Data.InjectionCount - 1;

                    InjectionSelected?.Invoke(null, SelectedPeak);
                }

                Graph.SetFocusedInjection(selectedPeak);

                if (IsInjectionZoomed) FocusPeak();
                if (CurrentVerticalZoomMode != VerticalZoomMode.Baseline) ShowAllVertical();
            }
        }

        public bool IsInjectionZoomed => CurrentHorizontalZoomMode == HorizontalZoomMode.SelectedPeak;

        public DataProcessingGraphView(IntPtr handle) : base(handle)
        {
            State = ProgramState.Process;

            NSEvent.AddLocalMonitorForEventsMatchingMask(NSEventMask.KeyDown, (NSEvent theEvent) => KeyDownEventHandler(theEvent));

            this.AddSubview(ZoomSelectionBox);
        }

        NSEvent KeyDownEventHandler(NSEvent theEvent)
        {
            if (StateManager.CurrentState != this.State) return theEvent;

            switch ((NSKey)theEvent.KeyCode)
            {
                case NSKey.Space:
                    if (SelectedPeak != -1 && IsInjectionZoomed)
                    {
                        Console.WriteLine("Copying integration length...");
                        var startDelay = Data.Injections[SelectedPeak].IntegrationStartDelay;
                        var length = Data.Injections[SelectedPeak].IntegrationEndOffset;
                        SelectedPeak++;
                        if (AppSettings.IntegrationRegionCopyIncludesStart)
                            Data.Injections[SelectedPeak].SetIntegrationStartTime(startDelay);
                        Data.Injections[SelectedPeak].SetIntegrationLengthByTime(length);
                        FocusPeak();

                        _ = Data.Processor.ProcessData();
                    }
                    break;
                case NSKey.LeftArrow:
                    SelectedPeak--;
                    FocusPeak();
                    return null;
                case NSKey.RightArrow:
                    SelectedPeak++;
                    FocusPeak();
                    return null;
            }

            return theEvent;
        }

        public void Initialize(ExperimentData experiment)
        {
            selectedPeak = -1;

            if (experiment != null && experiment.HasThermogram)
            {
                base.Graph = new BaselineFittingGraph(experiment, this);
            }
            else base.Graph = null;

            CurrentVerticalZoomMode = VerticalZoomMode.AllData;
            CurrentHorizontalZoomMode = HorizontalZoomMode.AllPeaks;
            ZoomModeChanged?.Invoke(this, EventArgs.Empty);
        }

        public void ZoomBaseline()
        {
            if (Data == null) return;
            if (Data.Processor.Interpolator?.Baseline == null || Data.Processor.Interpolator?.Baseline.Count == 0) return;
            if (Graph == null) return;

            var xmin = Graph.XAxis.Min;
            var xmax = Graph.XAxis.Max;

            var baselinemin = double.MaxValue;
            var baselinemax = double.MinValue;

            if (!ShowBaselineCorrected)
                for (int i = 0; i < Data.DataPoints.Count; i++)
                {
                    DataPoint dp = Graph.DataPoints[i];

                    if (dp.Time < xmin) continue;
                    else if (dp.Time > xmax) break;

                    var blp = Data.Processor.Interpolator.Baseline[i];

                    if (blp < baselinemin) baselinemin = (double)blp;
                    if (blp > baselinemax) baselinemax = (double)blp;
                }
            else
            {
                baselinemin = 0;
                baselinemax = 0;
            }

            var datapoints = Data.Processor.Interpolator.GetInterpolatedDataPoints(xmin, xmax);

            if (datapoints.Count == 0) return;

            var mean = datapoints.Select(dp => dp.Power).Average();
            var ymin = datapoints.Min(dp => dp.Power);
            var ymax = datapoints.Max(dp => dp.Power);

            var delta = Math.Min(mean - ymin, ymax - mean);

            Graph.SetYAxisRange(baselinemin - delta * 3f, baselinemax + delta * 3f);

            CurrentVerticalZoomMode = VerticalZoomMode.Baseline;

            Invalidate();
            ZoomModeChanged?.Invoke(this, EventArgs.Empty);
        }

        public void ShowAllVertical()
        {
            if (Data == null) return;
            if (Graph == null) return;

            var xmin = Graph.XAxis.Min;
            var xmax = Graph.XAxis.Max;

            var dps = Graph.DataPoints.Where(dp => dp.Time > xmin && dp.Time < xmax);

            if (dps.Count() < 2) return;

            Graph.SetYAxisRange(dps.Min(dp => dp.Power), dps.Max(dp => dp.Power), buffer: true);

            CurrentVerticalZoomMode = VerticalZoomMode.AllData;

            Invalidate();
            ZoomModeChanged?.Invoke(this, EventArgs.Empty);
        }

        public void ApplyVerticalZoomMode(VerticalZoomMode zoomMode)
        {
            switch (zoomMode)
            {
                case VerticalZoomMode.Baseline:
                    ZoomBaseline();
                    break;
                case VerticalZoomMode.AllData:
                    ShowAllVertical();
                    break;
            }
        }

        public void FocusPeak()
        {
            if (Data == null) return;
            if (SelectedPeak == -1) return;
            if (Graph == null) return;
            int idx1 = SelectedPeak - PeakZoomWidth;
            int idx2 = SelectedPeak + PeakZoomWidth;

            if (idx1 < 0) idx1 = 0;
            if (idx2 >= Data.InjectionCount) idx2 = Data.InjectionCount - 1;

            var inj_first = Data.Injections[idx1];
            var inj_last = Data.Injections[idx2];

            //If first injection is #0, then start draw at t = 0
            Graph.SetXAxisRange(idx1 == 0 ? 0 : inj_first.Time - inj_first.Delay * 0.2f, inj_last.Time + inj_last.Delay * 1.2f);

            CurrentHorizontalZoomMode = HorizontalZoomMode.SelectedPeak;

            if (CurrentVerticalZoomMode == VerticalZoomMode.Baseline) ZoomBaseline();
            else ShowAllVertical();

            Invalidate();
            ZoomModeChanged?.Invoke(this, EventArgs.Empty);
        }

        public void UnfocusPeak()
        {
            if (Data == null) return;
            if (Graph == null) return;

            Graph.SetXAxisRange(Graph.DataPoints.Min(dp => dp.Time), Graph.DataPoints.Max(dp => dp.Time), buffer: false);

            CurrentHorizontalZoomMode = HorizontalZoomMode.AllPeaks;

            if (CurrentVerticalZoomMode == VerticalZoomMode.Baseline) ZoomBaseline();
            else ShowAllVertical();

            Invalidate();
            ZoomModeChanged?.Invoke(this, EventArgs.Empty);
        }

        void ZoomRegion(CGRect region)
        {
            if (Data == null) return;
            if (region.Width < 10) return; //dont zoom too much please
            if (Graph == null) return;

            Graph.SetXAxisRange(region.Left, region.Right);
            Graph.SetYAxisRange(region.Bottom, region.Top);

            CurrentVerticalZoomMode = VerticalZoomMode.None;
            CurrentHorizontalZoomMode = HorizontalZoomMode.None;

            Invalidate();
            ZoomModeChanged?.Invoke(this, EventArgs.Empty);
        }

        public void SetFeatureVisibility(NSSegmentedControl sender)
        {
            SetFeatureVisibility(sender.IsSelectedForSegment(0), sender.IsSelectedForSegment(1), sender.IsSelectedForSegment(2), false);
        }

        public void SetFeatureVisibility(bool baseline, bool injections, bool corrected, bool cursorinfo)
        {
            var verticalZoomMode = CurrentVerticalZoomMode;

            ShowBaseline = baseline;
            ShowInjections = injections;
            ShowBaselineCorrected = corrected;
            DrawCursorPositionInfo = cursorinfo;

            ApplyVerticalZoomMode(verticalZoomMode);

            Invalidate();
        }

        public override void MouseMoved(NSEvent theEvent)
        {
            base.MouseMoved(theEvent);

            if (Data == null) return;
            if (Graph == null) return;

            var b = Graph.CursorFeatureFromPos(CursorPositionInView);
            var update = Graph.SetCursorInfo(CursorPositionInView);
            var hoverChanged = Graph.SetHoverFeature(b);

            if (b.IsMouseOverFeature)
            {
                if (b.Type == MouseOverFeatureEvent.FeatureType.BaselineSplinePoint) SetSplinePointCursor();
                else if (b.Type == MouseOverFeatureEvent.FeatureType.BaselineSplineHandle) SplinePointVerticalMoveCursor.Set();
                else if (b.Type == MouseOverFeatureEvent.FeatureType.IntegrationRangeMarker) NSCursor.ResizeLeftRightCursor.Set();
            }
            else if (update) NSCursor.CrosshairCursor.Set();
            else NSCursor.ArrowCursor.Set();

            if (update || hoverChanged) Invalidate();
        }

        public override void MouseDown(NSEvent theEvent)
        {
            base.MouseDown(theEvent);

            if (Data == null) return;
            if (Graph == null) return;

            SelectedFeature = Graph.CursorFeatureFromPos(CursorPositionInView, true);

            if (SelectedFeature.Type == MouseOverFeatureEvent.FeatureType.DragZoom)
                ZoomDragCursor.Set();
        }

        public override void RightMouseDown(NSEvent theEvent)
        {
            base.RightMouseDown(theEvent);

            if (Data == null) return;
            if (Graph == null) return;

            var feature = Graph.CursorFeatureFromPos(CursorPositionInView);

            if (feature.IsMouseOverFeature)
            {
                if (feature.Type == MouseOverFeatureEvent.FeatureType.BaselineSplinePoint)
                {
                    var splinePoint = Data.Processor.Interpolator.SplineInterpolator.SplinePoints[feature.FeatureID];

                    NSMenu menu = new NSMenu("Spline Point Options");
                    if (splinePoint.Locked)
                        menu.AddItem(new NSMenuItem("Unlock", (s, e) => { splinePoint.Unlock(); splinePoint.UnlockSlope(); _ = Data.Processor.ProcessData(); }));
                    else
                        menu.AddItem(new NSMenuItem("Lock", (s, e) => { splinePoint.Lock(); _ = Data.Processor.ProcessData(false); }));
                    menu.AddItem(new NSMenuItem(splinePoint.Linear ? "Unmark Linear" : "Mark Linear", (s, e) =>
                    {
                        splinePoint.Linear = !splinePoint.Linear;
                        if (splinePoint.Linear) splinePoint.Lock();
                        _ = Data.Processor.ProcessData(false);
                    }));
                    menu.AddItem(new NSMenuItem("Remove", (s, e) => { Data.Processor.Interpolator.SplineInterpolator.RemoveSplinePoint(feature.FeatureID); }));
                    WillOpenMenu(menu, theEvent);

                    NSMenu.PopUpContextMenu(menu, theEvent, this);
                }
            }
            else if (Data.Processor.Interpolator is SplineInterpolator)
            {
                var xfraction = (CursorPositionInView.X - Graph.Frame.X) / Graph.Frame.Width;
                var time = xfraction * (Graph.XAxis.Max - Graph.XAxis.Min) + Graph.XAxis.Min;

                NSMenu menu = new NSMenu("New Spline Point");
                menu.AddItem(new NSMenuItem("New Spline Point..."));
                menu.AddItem(new NSMenuItem("at data", (s, e) => { (Data.Processor.Interpolator as SplineInterpolator).InsertSplinePoint(time, true); }) { IndentationLevel = 1 });
                menu.AddItem(new NSMenuItem("at baseline", (s, e) => { (Data.Processor.Interpolator as SplineInterpolator).InsertSplinePoint(time, false); }) { IndentationLevel = 1 });
                NSMenu.PopUpContextMenu(menu, theEvent, this);
            }
        }

        public override void MouseDragged(NSEvent theEvent)
        {
            base.MouseDragged(theEvent);

            if (Graph == null) return;
            if (SelectedFeature == null) return;

            var position = CursorPositionInView;

            var factor = (theEvent.ModifierFlags & NSEventModifierMask.ShiftKeyMask) != 0 ? SplineDragSlowFactor : 1.0;
            // Convert vertical cursor movement (pixels) into graph Y units.
            // Using PointsPerUnit means the feature will follow the cursor 1:1 in screen space.
            var deltaYpx = position.Y - SelectedFeature.ClickCursorPosition.Y;
            var yUnitsPerPixel = Graph.PointsPerUnit.Height != 0 ? 1.0 / (double)Graph.PointsPerUnit.Height : 0.0;
            var deltaYUnits = deltaYpx * yUnitsPerPixel * factor;
            var deltaXpx = position.X - SelectedFeature.ClickCursorPosition.X;
            var xUnitsPerPixel = Graph.PointsPerUnit.Width != 0 ? 1.0 / (double)Graph.PointsPerUnit.Width : 0.0;
            var deltaXUnits = deltaXpx * xUnitsPerPixel * factor;

            var shouldRefreshSplineBaseline = false;

            switch (SelectedFeature.Type)
            {
                case MouseOverFeatureEvent.FeatureType.BaselineSplinePoint:
                    {
                        if (Data.Processor.Interpolator is not SplineInterpolator splineInterpolator) break;

                        var feature = splineInterpolator.SplinePoints[SelectedFeature.FeatureID];
                        feature.Power = SelectedFeature.FeatureReferenceValue + deltaYUnits;
                        if (splineInterpolator.AllowPointTimeDragging)
                            feature.Time = ClampSplinePointDragTime(splineInterpolator, SelectedFeature.FeatureID, SelectedFeature.SecondaryFeatureReferenceValue + deltaXUnits);
                        feature.Lock();
                        shouldRefreshSplineBaseline = true;
                        break;
                    }
                case MouseOverFeatureEvent.FeatureType.BaselineSplineHandle:
                    {
                        bool invert = SelectedFeature.SubID == 0;

                        var feature = (Data.Processor.Interpolator as SplineInterpolator).SplinePoints[SelectedFeature.FeatureID];

                        // Handle visualization uses an average delay/5 as a time-length for handle placement.
                        // A slope change of dSlope changes the handle point Y by dSlope * handleLengthTime.
                        var handleLengthTime = Data.Injections.Average(inj => inj.Delay / 5);
                        var dSlope = handleLengthTime != 0 ? (deltaYUnits / handleLengthTime) : 0.0;
                        if (invert) dSlope = -dSlope;

                        feature.Slope = SelectedFeature.FeatureReferenceValue + dSlope;
                        feature.Lock();
                        feature.LockSlope();
                        shouldRefreshSplineBaseline = true;
                        break;
                    }
                case MouseOverFeatureEvent.FeatureType.IntegrationRangeMarker:
                    {
                        Data.Processor.IntegrationLengthMode = InjectionData.IntegrationLengthMode.Time;
                        bool start = SelectedFeature.SubID == 0;

                        var xfraction = (CursorPositionInView.X - Graph.Frame.X) / Graph.Frame.Width;
                        var time = xfraction * (Graph.XAxis.Max - Graph.XAxis.Min) + Graph.XAxis.Min;
                        var inj = Data.Injections[SelectedFeature.FeatureID];

                        if (start) inj.SetIntegrationStartTime((float)time - inj.Time);
                        else inj.SetIntegrationLengthByTime((float)time - inj.Time);

                        InjectionSelected?.Invoke(null, SelectedFeature.FeatureID);

                        Data.Processor.IntegratePeaks(false);

                        break;
                    }
                case MouseOverFeatureEvent.FeatureType.DragZoom:
                    {
                        ZoomDragCursor.Set();

                        ZoomSelectionBox.Frame = SelectedFeature.GetZoomRect(Graph, position);
                        ZoomSelectionBox.Hidden = false;

                        break;
                    }

            }

            if (shouldRefreshSplineBaseline) RefreshSplineBaseline();

            Graph.SetCursorInfo(CursorPositionInView);

            Invalidate();

            BaselineChanged?.Invoke(SelectedFeature, null);
        }

        public override void MouseUp(NSEvent theEvent)
        {
            base.MouseUp(theEvent);

            if (Graph == null) return;

            if (MouseDidDrag)
            {
                switch (SelectedFeature.Type)
                {
                    case MouseOverFeatureEvent.FeatureType.BaselineSplineHandle:
                    case MouseOverFeatureEvent.FeatureType.BaselineSplinePoint: UpdateSplineHandle(); break;
                    case MouseOverFeatureEvent.FeatureType.IntegrationRangeMarker:
                        if (Data.Processor.BaselineCompleted)
                            if (Data.Processor.DiscardIntegratedPoints) _ = Data.Processor.ProcessData();
                            else Data.Processor.IntegratePeaks(); //Don't integrate twice
                        break;
                    case MouseOverFeatureEvent.FeatureType.DragZoom:
                        ZoomSelectionBox.Hidden = true;
                        ZoomRegion(SelectedFeature.GetZoomRegion(Graph, CursorPositionInView));
                        Console.WriteLine(SelectedFeature.GetZoomRegion(Graph, CursorPositionInView));
                        break;
                }

                if (Data == null) return;

                var b = Graph.CursorFeatureFromPos(CursorPositionInView);
                Graph.SetHoverFeature(b);

                if (b.IsMouseOverFeature)
                {
                    if (b.Type == MouseOverFeatureEvent.FeatureType.BaselineSplinePoint) SetSplinePointCursor();
                    else if (b.Type == MouseOverFeatureEvent.FeatureType.BaselineSplineHandle) SplinePointVerticalMoveCursor.Set();
                    else if (b.Type == MouseOverFeatureEvent.FeatureType.IntegrationRangeMarker) NSCursor.ResizeLeftRightCursor.Set();
                }
                else NSCursor.ArrowCursor.Set();
            }
            else if (ShowInjections)
            {
                var xfraction = (CursorPositionInView.X - Graph.Frame.X) / Graph.Frame.Width;
                var time = xfraction * (Graph.XAxis.Max - Graph.XAxis.Min) + Graph.XAxis.Min;

                var clickedinj = Data.Injections.Where(inj => inj.Time < time && inj.Time + inj.Delay > time);

                if (clickedinj.Count() != 0)
                {
                    SelectedPeak = clickedinj.First().ID;
                    InjectionSelected?.Invoke(clickedinj.First(), clickedinj.First().ID);
                }

                if (theEvent.ClickCount > 1 && SelectedPeak != -1) FocusPeak(); // Double click
            }
        }

        public override void MouseExited(NSEvent theEvent)
        {
            if (Graph == null) return;

            base.MouseExited(theEvent);

            Graph.SetHoverFeature(null);

            Invalidate();
        }

        async void UpdateSplineHandle()
        {
            if (Graph == null) return;

            await Data.Processor.Interpolator.Interpolate(new System.Threading.CancellationToken(), false);

            Data.Processor.SubtractBaseline();

            Invalidate();

            Data.Processor.IntegratePeaks();
        }

        void RefreshSplineBaseline()
        {
            if (Data?.Processor?.Interpolator is not SplineInterpolator splineInterpolator) return;

            splineInterpolator.RefreshBaselineFromCurrentSplinePoints();
            Data.Processor.SubtractBaseline();
        }

        void SetSplinePointCursor()
        {
            if (Data?.Processor?.Interpolator is SplineInterpolator splineInterpolator && splineInterpolator.AllowPointTimeDragging)
                SplinePointMoveCursor.Set();
            else
                SplinePointVerticalMoveCursor.Set();
        }

        static NSCursor CreateSplinePointMoveCursor() => CreateSplinePointCursor(includeHorizontalArrows: true);

        static NSCursor CreateSplinePointVerticalMoveCursor() => CreateSplinePointCursor(includeHorizontalArrows: false);

        static NSCursor CreateZoomDragCursor()
        {
            var size = new CGSize(ZoomDragCursorSize, ZoomDragCursorSize);
            var center = new CGPoint(size.Width / 2, size.Height / 2);
            var image = new NSImage(size);

            image.LockFocus();
            DrawZoomDragCursorGlyph(NSColor.White, 4f);
            DrawZoomDragCursorGlyph(NSColor.Black, 2f);
            image.UnlockFocus();

            return new NSCursor(image, center);
        }

        static void DrawZoomDragCursorGlyph(NSColor color, float lineWidth)
        {
            var gc = NSGraphicsContext.CurrentContext.CGContext;
            gc.SetStrokeColor(color.CGColor);
            gc.SetLineWidth(lineWidth);
            gc.SetLineCap(CGLineCap.Round);
            gc.SetLineJoin(CGLineJoin.Round);

            gc.BeginPath();
            gc.AddEllipseInRect(new CGRect(5f, 8f, 10f, 10f));
            gc.MoveTo(14f, 7f);
            gc.AddLineToPoint(20f, 1f);
            gc.MoveTo(10f, 11f);
            gc.AddLineToPoint(10f, 15f);
            gc.MoveTo(8f, 13f);
            gc.AddLineToPoint(12f, 13f);
            gc.StrokePath();
        }

        static NSCursor CreateSplinePointCursor(bool includeHorizontalArrows)
        {
            var size = new CGSize(SplinePointMoveCursorSize, SplinePointMoveCursorSize);
            var center = new CGPoint(size.Width / 2, size.Height / 2);
            var image = new NSImage(size);

            image.LockFocus();
            DrawSplinePointMoveCursorGlyph(NSColor.White, 4f, center, includeHorizontalArrows);
            DrawSplinePointMoveCursorGlyph(NSColor.Black, 2f, center, includeHorizontalArrows);
            image.UnlockFocus();

            return new NSCursor(image, center);
        }

        static void DrawSplinePointMoveCursorGlyph(NSColor color, float lineWidth, CGPoint center, bool includeHorizontalArrows)
        {
            const float inner = 4f;
            const float outer = 9f;
            const float arrowOffset = 3f;

            var gc = NSGraphicsContext.CurrentContext.CGContext;
            gc.SetStrokeColor(color.CGColor);
            gc.SetLineWidth(lineWidth);
            gc.SetLineCap(CGLineCap.Round);
            gc.SetLineJoin(CGLineJoin.Round);

            gc.BeginPath();

            DrawCursorArrow(gc, center, new CGPoint(center.X, center.Y + inner), new CGPoint(center.X, center.Y + outer), arrowOffset);
            DrawCursorArrow(gc, center, new CGPoint(center.X, center.Y - inner), new CGPoint(center.X, center.Y - outer), arrowOffset);
            if (includeHorizontalArrows)
            {
                DrawCursorArrow(gc, center, new CGPoint(center.X - inner, center.Y), new CGPoint(center.X - outer, center.Y), arrowOffset);
                DrawCursorArrow(gc, center, new CGPoint(center.X + inner, center.Y), new CGPoint(center.X + outer, center.Y), arrowOffset);
            }

            gc.StrokePath();
        }

        static void DrawCursorArrow(CGContext gc, CGPoint center, CGPoint shaftStart, CGPoint arrowTip, float arrowOffset)
        {
            gc.MoveTo(shaftStart.X, shaftStart.Y);
            gc.AddLineToPoint(arrowTip.X, arrowTip.Y);

            var dx = arrowTip.X - center.X;
            var dy = arrowTip.Y - center.Y;

            if (Math.Abs(dx) > Math.Abs(dy))
            {
                var direction = Math.Sign(dx);
                gc.MoveTo(arrowTip.X, arrowTip.Y);
                gc.AddLineToPoint(arrowTip.X - direction * arrowOffset, arrowTip.Y + arrowOffset);
                gc.MoveTo(arrowTip.X, arrowTip.Y);
                gc.AddLineToPoint(arrowTip.X - direction * arrowOffset, arrowTip.Y - arrowOffset);
            }
            else
            {
                var direction = Math.Sign(dy);
                gc.MoveTo(arrowTip.X, arrowTip.Y);
                gc.AddLineToPoint(arrowTip.X + arrowOffset, arrowTip.Y - direction * arrowOffset);
                gc.MoveTo(arrowTip.X, arrowTip.Y);
                gc.AddLineToPoint(arrowTip.X - arrowOffset, arrowTip.Y - direction * arrowOffset);
            }
        }

        double ClampSplinePointDragTime(SplineInterpolator splineInterpolator, int pointIndex, double proposedTime)
        {
            var points = splineInterpolator.SplinePoints;
            if (Data?.DataPoints == null || Data.DataPoints.Count == 0) return proposedTime;
            if (pointIndex < 0 || pointIndex >= points.Count) return proposedTime;

            var minimumSpacing = Math.Max(Data.TimeStep * MinimumSplinePointTimeSpacingMultiplier, double.Epsilon);
            double minTime = Data.DataPoints.First().Time;
            double maxTime = Data.DataPoints.Last().Time;

            if (pointIndex > 0) minTime = points[pointIndex - 1].Time + minimumSpacing;
            if (pointIndex < points.Count - 1) maxTime = points[pointIndex + 1].Time - minimumSpacing;

            if (minTime > maxTime) return points[pointIndex].Time;

            return Math.Min(maxTime, Math.Max(minTime, proposedTime));
        }
    }
